public class ZHtest3_jjj {
	public static void main(String[] args) {
		for(int a=1;a<=9;a++) {
			for(int b=1;b<=9;b++) {
				System.out.print(b+'X'+a+'='+a*b+' ');
				if(a*b<10) {
					System.out.print(' ');
				}
				if(a==b) {
					System.out.println();
					break;
				}
			}
		}
	}
}

